787 ///   0 on the RHS is the identity value (i.e add, xor, shl, etc...)
788 ///   C1 and C2 are both powers of 2
789 /// where:
790 ///   IF C2 u>= C1
791 ///     C3 = Log(C2) - Log(C1)
792 ///   ELSE
793 ///     C3 = Log(C1) - Log(C2)
