853   } else
854     V = Builder.CreateZExtOrTrunc(V, Y->getType());
855 
856   if (NeedXor)
857     V = Builder.CreateXor(V, *C2);
858 
859   auto *Res = Builder.CreateBinOp(BinOp->getOpcode(), Y, V);
860   if (auto *BO = dyn_cast<BinaryOperator>(Res))
861     BO->copyIRFlags(BinOp);
862   return Res;
